      "meta_description": "Learn how timebanking works — give an hour, earn a credit, get help. Join a community built on reciprocity and trust.",
      "page_title": "Timebanking Guide",
      "proven_impact_heading": "Proven Impact",
      "proven_impact_subtitle": "Independent research confirms the transformative power of timebanking.",
      "stat_100_description": "Members report feeling better connected and supported",
      "stat_100_label": "Improved Wellbeing",
      "stat_161_description": "For every €1 invested, €16 of social value is created",
      "stat_161_label": "Social Return on Investment",
      "stat_95_description": "Members feel more integrated in their community",
      "stat_95_label": "Socially Connected",
      "step_0_description": "Share a skill you love — from practical help to a friendly chat or a lift to the shops.",
      "step_0_title": "Give an Hour",
      "step_1_description": "You automatically earn one Time Credit for every hour you spend helping another member.",
      "step_1_title": "Earn a Credit",
      "step_2_description": "Spend your credit to get support, learn a new skill, or join a community work day.",
      "step_2_title": "Get Help",
      "value_0_description": "Everyone has something valuable to offer. Timebanking recognises the unique contributions of every member, regardless of background or circumstance.",
      "value_0_title": "We Are All Assets",
      "value_1_description": "Raising children, caring for elders, volunteering, and community building — timebanking values the essential work that keeps communities strong.",
      "value_1_title": "Redefining Work",
      "value_2_description": "Giving and receiving go hand in hand. When you help someone, you create a ripple of goodwill that comes back to strengthen the whole community.",
      "value_2_title": "Reciprocity",
      "value_3_description": "Timebanking weaves a web of trust and mutual support. Every exchange builds social capital and creates lasting connections between neighbours.",
      "value_3_title": "Social Networks",
      "values_heading": "Our Fundamental Values",
      "values_subtitle": "Timebanking is built on four core values that guide everything we do."
