        "content_item2": "Resources and knowledge base — structured articles and shared resource library",
        "content_item3": "Help center — documentation hub and FAQ",
        "content_item4": "Newsletter system — email campaigns with A/B testing, smart segments, geo targeting, recurring sends, templates, and full open/click analytics",
        "content_item5": "AI Chat — AI-powered assistant for platform guidance",
        "content_item6": "Custom pages — tenant-managed CMS pages",
        "content_item7": "Legal hub — versioned legal documents with acceptance gates and audit trail",
